function solve(words) {
    const n = words.length;
    const answer = new Array(n).fill(0);

    // Preprocess to build a trie or use a prefix array
    // For this problem, we'll use a prefix array approach

    // Build a prefix array for each word
    const prefix = [];
    for (let i = 0; i < n; i++) {
        let curr = words[i];
        let prefixStr = "";
        while (curr.length > 0) {
            prefixStr = curr[0] + prefixStr;
            curr = curr.slice(1);
            if (prefixStr.length > 0) {
                prefix.push(prefixStr);
            }
        }
    }

    // Build a trie for all words
    const trie = new Map();
    for (let i = 0; i < n; i++) {
        let node = trie;
        for (let c of words[i]) {
            if (!node.has(c)) {
                node.set(c, new Map());
            }
            node = node.get(c);
        }
    }

    // Function to find the longest common prefix between two words
    function lcp(w1, w2) {
        let l = 0;
        while (l < w1.length && l < w2.length && w1[l] === w2[l]) {
            l++;
        }
        return l;
    }

    // For each index i, simulate removing it and compute the answer
    for (let i = 0; i < n; i++) {
        let maxLcp = 0;
        let prev = words[0];
        let next = words[1];

        for (let j = 0; j < n; j++) {
            if (j === i) continue;
            if (j > 0) {
                let curr = words[j];
                let currLcp = lcp(prev, curr);
                if (currLcp > maxLcp) {
                    maxLcp = currLcp;
                }
            }
            prev = words[j];
        }
        answer[i] = maxLcp;
    }

    return answer;
}

