fun solve(words: Array<String>): Array<Long> {
    val n = words.size
    val answer = Array(n) { 0L }

    // Preprocess to build a prefix array for each word
    val prefix = mutableListOf<String>()
    for (i in 0 until n) {
        val curr = words[i]
        var prefixStr = ""
        var temp = curr
        while (temp.isNotEmpty()) {
            prefixStr = temp.first() + prefixStr
            temp = temp.substring(1)
            if (prefixStr.isNotEmpty()) {
                prefix.add(prefixStr)
            }
        }
    }

    // Build a trie for all words
    val trie = mutableMapOf<Char, MutableMap<Char, Int>>()
    for (i in 0 until n) {
        var node = trie
        for (c in words[i]) {
            if (!node.containsKey(c)) {
                node[c] = mutableMapOf()
            }
            node = node[c]!!
        }
    }

    // Function to find the longest common prefix between two words
    fun lcp(w1: String, w2: String): Int {
        var l = 0
        while (l < w1.length && l < w2.length && w1[l] == w2[l]) {
            l++
        }
        return l
    }

    // For each index i, simulate removing it and compute the answer
    for (i in 0 until n) {
        var maxLcp = 0L
        var prev: String? = null
        for (j in 0 until n) {
            if (j == i) continue
            if (prev != null) {
                val curr = words[j]
                val currLcp = lcp(prev, curr)
                if (currLcp > maxLcp) {
                    maxLcp = currLcp.toLong()
                }
            }
            prev = words[j]
        }
        answer[i] = maxLcp
    }

    return answer
}
